#!/usr/bin/env node
// ─────────────────────────────────────────────────────────────────────────────
// Crumb docs site — sync a whitelisted subset of docs/ into docs-site/docs/architecture/
//
// The docs site (docs-site/) publishes a curated Architecture section built
// from this repo's internal engineering docs (docs/). To avoid ever
// publishing something not meant for a public audience (in-progress plans,
// audits, legal reviews), only an explicit whitelist below is copied, and
// each copy gets a generated "do not edit here" banner pointing back at its
// source. See the docs-site README for the site's build model.
//
// Zero dependencies (Node's built-in fs/path only), so it can run in CI with
// nothing but `actions/setup-node` and no docs-site npm install.
//
// Usage:
//   node scripts/sync-arch-docs.mjs
//
// Missing whitelist entries are skipped gracefully (not every doc exists in
// every checkout state), with a one-line notice, not a hard failure — new
// docs get added to the whitelist as they're written, not before.
// ─────────────────────────────────────────────────────────────────────────────

import { readFileSync, writeFileSync, existsSync, mkdirSync } from 'node:fs';
import { dirname, join } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const REPO_ROOT = join(__dirname, '..');
const SOURCE_DIR = join(REPO_ROOT, 'docs');
const DEST_DIR = join(REPO_ROOT, 'docs-site', 'docs', 'architecture');

// Whitelist: [source filename in docs/, destination doc-id/slug in
// docs-site/docs/architecture/, sidebar title]. Order here is the order
// they're listed in docs-site/sidebars.js (kept in sync by hand; see the
// comment at the bottom of this file if that ever drifts).
const WHITELIST = [
  {
    src: 'DECISIONS.md',
    dest: 'decisions.md',
    title: 'Decision log',
    slug: '/architecture/decisions',
  },
  {
    src: 'RECORDER-CORRECTNESS.md',
    dest: 'recorder-correctness.md',
    title: 'Recorder correctness',
    slug: '/architecture/recorder-correctness',
  },
  {
    src: 'MOTION-RECORDING.md',
    dest: 'motion-recording.md',
    title: 'Motion recording mechanism',
    slug: '/architecture/motion-recording',
  },
];

function banner(srcName) {
  // MDX-safe comment: Docusaurus v3 parses .md files as MDX by default, and a
  // raw HTML comment (`<!-- -->`) immediately after front matter has been
  // observed to trip the MDX/JSX parser ("Unexpected character `!`") on some
  // inputs. `{/* */}` is the always-safe MDX comment form.
  return [
    '{/*',
    `  AUTO-COPIED from docs/${srcName} by scripts/sync-arch-docs.mjs.`,
    '  Do NOT edit this file directly, your changes will be overwritten the',
    '  next time the docs site is built. Edit the source file in docs/ instead.',
    '*/}',
    '',
  ].join('\n');
}

function frontMatter(title, slug) {
  return ['---', `title: ${title}`, `sidebar_label: ${title}`, `slug: ${slug}`, '---', ''].join(
    '\n'
  );
}

// These are hand-written engineering docs full of prose like a literal
// "...for {camera}" placeholder outside of any code span or fence — perfectly
// normal Markdown, but not valid MDX (Docusaurus parses .md as MDX by
// default, and bare `{...}` outside code is treated as a JS expression,
// throwing "ReferenceError: camera is not defined" at render time). Per-file
// `format: md` front matter did not reliably suppress this against this
// site's toolchain, so instead escape literal `{`/`}` to HTML entities
// everywhere EXCEPT inside fenced code blocks and inline code spans, where
// the original characters must survive untouched for the code to render
// correctly. This only ever runs against the generated copy, never the
// source file in docs/.
function escapeMdxBraces(markdown) {
  const lines = markdown.split('\n');
  let inFence = false;
  const out = lines.map((line) => {
    const fenceMatch = /^\s*(```|~~~)/.test(line);
    if (fenceMatch) {
      inFence = !inFence;
      return line;
    }
    if (inFence) {
      return line;
    }
    // Outside a fence: walk the line, toggling on backtick-delimited inline
    // code spans, and only escape braces in the non-code segments.
    let result = '';
    let inCode = false;
    for (let i = 0; i < line.length; i += 1) {
      const ch = line[i];
      if (ch === '`') {
        inCode = !inCode;
        result += ch;
      } else if (!inCode && ch === '{') {
        result += '&#123;';
      } else if (!inCode && ch === '}') {
        result += '&#125;';
      } else {
        result += ch;
      }
    }
    return result;
  });
  return out.join('\n');
}

function main() {
  if (!existsSync(DEST_DIR)) {
    mkdirSync(DEST_DIR, { recursive: true });
  }

  let copied = 0;
  let skipped = 0;

  for (const entry of WHITELIST) {
    const srcPath = join(SOURCE_DIR, entry.src);
    const destPath = join(DEST_DIR, entry.dest);

    if (!existsSync(srcPath)) {
      console.log(`[sync-arch-docs] skip (not found): docs/${entry.src}`);
      skipped += 1;
      continue;
    }

    const rawBody = readFileSync(srcPath, 'utf8');
    const body = escapeMdxBraces(rawBody);
    const out = frontMatter(entry.title, entry.slug) + banner(entry.src) + body;
    writeFileSync(destPath, out, 'utf8');
    console.log(`[sync-arch-docs] copied docs/${entry.src} -> docs-site/docs/architecture/${entry.dest}`);
    copied += 1;
  }

  console.log(`[sync-arch-docs] done: ${copied} copied, ${skipped} skipped (missing source).`);
}

main();

// ─────────────────────────────────────────────────────────────────────────────
// Note on committed-vs-generated (see the docs-site README): the three
// generated files above (decisions.md, recorder-correctness.md,
// motion-recording.md) are gitignored in docs-site/.gitignore
// and regenerated by this script as the first step of every build (local,
// CI, and the docs.yml workflow), so they can never drift stale in git while
// their sources keep changing. Only docs-site/docs/architecture/index.md
// (the hand-written section landing page) is committed normally.
// If you add a new whitelist entry above, also add its doc id to
// docs-site/sidebars.js under the Architecture category.
// ─────────────────────────────────────────────────────────────────────────────
